import { LayoutAdapter } from './16.1.21-SETCONTENTVIEW-ADAPTER/coding';
import { ViewFinderAdapter } from './16.1.21-FINDVIEWBYID-ADAPTER/coding';
import { ButtonAdapter } from './16.1.21-BUTTON-ADAPTER/coding';
import { TextViewAdapter } from './16.1.22-TEXTVIEW-ADAPTER/coding';
import { TextClockAdapter } from './16.1.22-TEXTCLOCK-ADAPTER/coding';
import { TimeZoneAdapter } from './16.1.22-TIMEZONE-ADAPTER/coding';
import { EventAdapter } from './16.1.23-ONCLICK-ADAPTER/coding';
